export enum AssetType {
  TW_STOCK = 'TW_STOCK',
  US_STOCK = 'US_STOCK',
  CASH_TWD = 'CASH_TWD',
  CASH_USD = 'CASH_USD',
  LOAN_TWD = 'LOAN_TWD' // New: Credit Loan / Liabilities
}

export interface Asset {
  id: string;
  type: AssetType;
  name: string; // Ticker or Name (e.g., AAPL, 2330, 信貸)
  shares: number; // For stocks. For loans, this can be 1.
  costBasis: number; // Avg cost. For loans, this can be the interest rate (optional usage)
  currentPrice: number; // Market price. For loans, this is the outstanding balance.
  note?: string;
}

export interface PortfolioSummary {
  totalAssetsTwd: number;
  totalLiabilitiesTwd: number;
  netWorthTwd: number;
  totalValueUsd: number; // Net worth in USD
  allocation: {
    name: string;
    value: number;
    color: string;
  }[];
}

export interface HistoryRecord {
  id: string;
  date: string; // YYYY-MM (e.g., "2023-10")
  totalAssets: number;
  totalLiabilities: number;
  netWorth: number;
  note?: string;
}

export interface GeminiAnalysisResult {
  markdown: string;
  loading: boolean;
  error?: string;
}

import React, { useMemo } from 'react';
import { Asset, AssetType } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { TrendingUp, Wallet, Globe, ArrowDownCircle, Activity, Landmark } from 'lucide-react';

interface DashboardProps {
  assets: Asset[];
  exchangeRate: number;
}

const PIE_COLORS = [
  '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', 
  '#06b6d4', '#84cc16', '#f97316', '#6366f1', '#14b8a6'
];

const Dashboard: React.FC<DashboardProps> = ({ assets, exchangeRate }) => {
  const summary = useMemo(() => {
    let twStockVal = 0;
    let usStockVal = 0;
    let cashVal = 0;
    let loanVal = 0;

    // Calculate total values by category
    assets.forEach(asset => {
      const val = (asset.type.includes('US') ? (asset.shares * asset.currentPrice) * exchangeRate : (asset.shares * asset.currentPrice));

      if (asset.type === AssetType.TW_STOCK) {
        twStockVal += val;
      } else if (asset.type === AssetType.US_STOCK) {
        usStockVal += val;
      } else if (asset.type === AssetType.CASH_TWD || asset.type === AssetType.CASH_USD) {
        // Correctly handle cash values (shares usually 1, but safeguard calculation)
        const cashAmt = asset.type === AssetType.CASH_USD ? asset.currentPrice * exchangeRate : asset.currentPrice;
        cashVal += cashAmt;
      } else if (asset.type === AssetType.LOAN_TWD) {
        loanVal += asset.currentPrice;
      }
    });

    const totalAssets = twStockVal + usStockVal + cashVal;
    const netWorth = totalAssets - loanVal;

    // Prepare data for individual asset allocation pie chart (Assets Only)
    const assetData = assets
        .filter(a => a.type !== AssetType.LOAN_TWD)
        .map(asset => {
            let val = 0;
            if (asset.type.includes('CASH') || asset.type.includes('LOAN')) {
                 val = asset.currentPrice;
            } else {
                 val = asset.shares * asset.currentPrice;
            }

            if (asset.type.includes('US')) {
                val *= exchangeRate;
            }
            return {
                name: asset.name,
                value: val,
            };
        })
        .sort((a, b) => b.value - a.value);

    return {
      totalAssetsTwd: totalAssets,
      totalLiabilitiesTwd: loanVal,
      netWorthTwd: netWorth,
      netWorthUsd: exchangeRate > 0 ? netWorth / exchangeRate : 0,
      debtRatio: totalAssets > 0 ? (loanVal / totalAssets) * 100 : 0,
      categoryAllocation: [
         { name: '台股', value: twStockVal },
         { name: '美股', value: usStockVal },
         { name: '現金', value: cashVal },
      ],
      assetAllocation: assetData.length > 0 ? assetData : [{ name: '無資產', value: 1 }]
    };
  }, [assets, exchangeRate]);

  const hasData = assets.filter(a => a.type !== AssetType.LOAN_TWD).length > 0;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
      {/* Net Worth Hero Card */}
      <div className="bg-slate-800 p-6 rounded-2xl shadow-lg lg:col-span-2 flex flex-col justify-between relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-5">
          <Activity size={120} />
        </div>

        <div className="mb-6">
          <h2 className="text-slate-400 text-sm font-medium uppercase tracking-wider mb-2">淨資產 (Net Worth)</h2>
          <div className="flex items-baseline gap-2">
            <span className="text-4xl md:text-5xl font-bold text-white">
              NT$ {summary.netWorthTwd.toLocaleString(undefined, { maximumFractionDigits: 0 })}
            </span>
          </div>
          <p className="text-slate-400 mt-2 text-sm">
            ≈ US$ {summary.netWorthUsd.toLocaleString(undefined, { maximumFractionDigits: 2 })}
          </p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 border-t border-slate-700/50 pt-6">
             <div className="bg-emerald-900/20 border border-emerald-500/20 p-3 rounded-lg">
                <div className="text-emerald-400 text-xs font-bold mb-1 flex items-center gap-1">
                    <TrendingUp size={14} /> 總資產 Assets
                </div>
                <div className="text-lg font-semibold text-emerald-100">
                    NT$ {summary.totalAssetsTwd.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                </div>
            </div>

            <div className="bg-rose-900/20 border border-rose-500/20 p-3 rounded-lg">
                <div className="text-rose-400 text-xs font-bold mb-1 flex items-center gap-1">
                    <ArrowDownCircle size={14} /> 總負債 Liabilities
                </div>
                <div className="text-lg font-semibold text-rose-100">
                    NT$ {summary.totalLiabilitiesTwd.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                </div>
            </div>

            <div className="bg-slate-700/30 p-3 rounded-lg flex flex-col justify-center">
                 <div className="flex justify-between items-center mb-1">
                    <span className="text-xs font-bold text-slate-400">負債比 (Debt Ratio)</span>
                    <span className={`text-xs font-bold ${summary.debtRatio > 50 ? 'text-rose-400' : 'text-slate-300'}`}>
                        {summary.debtRatio.toFixed(1)}%
                    </span>
                 </div>
                 <div className="w-full bg-slate-600 rounded-full h-2">
                    <div 
                        className={`h-2 rounded-full ${summary.debtRatio > 50 ? 'bg-rose-500' : 'bg-indigo-500'}`} 
                        style={{ width: `${Math.min(summary.debtRatio, 100)}%` }}
                    ></div>
                 </div>
            </div>
        </div>
      </div>

      {/* Allocation Chart */}
      <div className="bg-slate-800 p-6 rounded-2xl shadow-lg flex flex-col items-center justify-center relative">
        <h3 className="text-slate-300 font-semibold mb-4 w-full text-left flex items-center gap-2">
            <Landmark size={18} />
            資產分布 (Assets Only)
        </h3>
        <div className="w-full h-48">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={summary.assetAllocation}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={hasData ? 2 : 0}
                dataKey="value"
                stroke="none"
              >
                {summary.assetAllocation.map((entry, index) => (
                  <Cell 
                    key={`cell-${index}`} 
                    fill={hasData ? PIE_COLORS[index % PIE_COLORS.length] : '#334155'} 
                  />
                ))}
              </Pie>
              {hasData && (
                  <Tooltip 
                    formatter={(value: number) => `NT$ ${Math.round(value).toLocaleString()}`}
                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f8fafc' }}
                    itemStyle={{ color: '#f8fafc' }}
                  />
              )}
            </PieChart>
          </ResponsiveContainer>
        </div>

        {!hasData && (
             <div className="absolute inset-0 flex items-center justify-center top-8 pointer-events-none">
                <span className="text-slate-500 text-sm">無資產資料</span>
             </div>
        )}

        {hasData && (
            <div className="mt-4 flex flex-wrap gap-2 justify-center text-[10px] text-slate-400 max-h-24 overflow-y-auto w-full custom-scrollbar">
                {summary.assetAllocation.map((entry, index) => (
                    <div key={index} className="flex items-center gap-1.5 bg-slate-700/30 px-2 py-1 rounded-full">
                        <div className="w-2 h-2 rounded-full" style={{ backgroundColor: PIE_COLORS[index % PIE_COLORS.length] }}></div>
                        <span className="truncate max-w-[80px]">{entry.name}</span>
                        <span className="opacity-70">{summary.totalAssetsTwd > 0 ? Math.round((entry.value / summary.totalAssetsTwd) * 100) : 0}%</span>
                    </div>
                    ))}
            </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Asset, AssetType } from '../types';
import { Trash2, Edit2, Plus, TrendingUp, TrendingDown, PieChart, Banknote } from 'lucide-react';

interface AssetListProps {
  assets: Asset[];
  typeFilter: 'STOCKS' | 'CASH' | 'LIABILITIES';
  exchangeRate: number;
  onDelete: (id: string) => void;
  onEdit: (asset: Asset) => void;
  onAdd: (type: AssetType) => void;
}

const AssetList: React.FC<AssetListProps> = ({ assets, typeFilter, exchangeRate, onDelete, onEdit, onAdd }) => {
  const [activeTab, setActiveTab] = useState<'ALL' | 'TW' | 'US'>('ALL');

  // Calculate Total Value for % calculation
  const totalCategoryValueTwd = useMemo(() => {
    return assets.reduce((sum, asset) => {
      // Filter sum based on current list type
      const isStock = asset.type === AssetType.TW_STOCK || asset.type === AssetType.US_STOCK;
      const isCash = asset.type === AssetType.CASH_TWD || asset.type === AssetType.CASH_USD;
      const isLoan = asset.type === AssetType.LOAN_TWD;

      if (typeFilter === 'STOCKS' && !isStock) return sum;
      if (typeFilter === 'CASH' && !isCash) return sum;
      if (typeFilter === 'LIABILITIES' && !isLoan) return sum;

      let val = 0;
      if (asset.type.includes('US')) {
        val = (asset.type.includes('CASH') ? asset.currentPrice : (asset.shares * asset.currentPrice)) * exchangeRate;
      } else {
         val = asset.type.includes('STOCK') ? (asset.shares * asset.currentPrice) : asset.currentPrice;
      }
      return sum + val;
    }, 0);
  }, [assets, exchangeRate, typeFilter]);

  const filteredAssets = assets.filter(asset => {
    if (typeFilter === 'LIABILITIES') {
        return asset.type === AssetType.LOAN_TWD;
    }
    if (typeFilter === 'CASH') {
      return asset.type === AssetType.CASH_TWD || asset.type === AssetType.CASH_USD;
    }
    // Stock Logic
    if (activeTab === 'TW') return asset.type === AssetType.TW_STOCK;
    if (activeTab === 'US') return asset.type === AssetType.US_STOCK;
    return asset.type === AssetType.TW_STOCK || asset.type === AssetType.US_STOCK;
  });

  const getCurrencySymbol = (type: AssetType) => {
    return (type === AssetType.US_STOCK || type === AssetType.CASH_USD) ? 'US$' : 'NT$';
  };

  const calculateGain = (asset: Asset) => {
    if (asset.type.includes('CASH') || asset.type.includes('LOAN')) return { gain: 0, percent: 0 };
    const currentVal = asset.shares * asset.currentPrice;
    const costVal = asset.shares * asset.costBasis;
    const gain = currentVal - costVal;
    const percent = costVal > 0 ? (gain / costVal) * 100 : 0;
    return { gain, percent };
  };

  const getHeaderTitle = () => {
      switch(typeFilter) {
          case 'STOCKS': return '證券部位 (Stock Holdings)';
          case 'CASH': return '現金部位 (Cash Positions)';
          case 'LIABILITIES': return '負債/信貸 (Liabilities)';
      }
  };

  const getHeaderDesc = () => {
    switch(typeFilter) {
        case 'STOCKS': return '管理你的股票與 ETF';
        case 'CASH': return '管理你的流動資金';
        case 'LIABILITIES': return '管理信貸與其他負債';
    }
  };

  return (
    <div className={`rounded-2xl shadow-lg overflow-hidden ${typeFilter === 'LIABILITIES' ? 'bg-rose-950/20 border border-rose-900/50' : 'bg-slate-800'}`}>
      {/* Header & Tabs */}
      <div className="p-6 border-b border-slate-700 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h3 className={`text-xl font-bold mb-1 ${typeFilter === 'LIABILITIES' ? 'text-rose-100' : 'text-white'}`}>
            {getHeaderTitle()}
          </h3>
          <p className={`text-sm ${typeFilter === 'LIABILITIES' ? 'text-rose-300/70' : 'text-slate-400'}`}>{getHeaderDesc()}</p>
        </div>

        <div className="flex items-center gap-3">
            {typeFilter === 'STOCKS' && (
                <div className="bg-slate-900 p-1 rounded-lg flex text-xs font-medium">
                    {(['ALL', 'TW', 'US'] as const).map(tab => (
                        <button
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`px-3 py-1.5 rounded-md transition-colors ${activeTab === tab ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                        >
                            {tab === 'TW' ? '🇹🇼 台股' : tab === 'US' ? '🇺🇸 美股' : '全部'}
                        </button>
                    ))}
                </div>
            )}

            {typeFilter === 'CASH' && (
                <div className="flex gap-2">
                     <button onClick={() => onAdd(AssetType.CASH_TWD)} className="bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 台幣
                    </button>
                    <button onClick={() => onAdd(AssetType.CASH_USD)} className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 美金
                    </button>
                </div>
            )}

            {typeFilter === 'LIABILITIES' && (
                <button onClick={() => onAdd(AssetType.LOAN_TWD)} className="bg-rose-600 hover:bg-rose-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                    <Plus size={16} /> 新增負債
                </button>
            )}

            {typeFilter === 'STOCKS' && (
                 <div className="flex gap-2">
                     <button onClick={() => onAdd(AssetType.TW_STOCK)} className="bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 台股
                    </button>
                    <button onClick={() => onAdd(AssetType.US_STOCK)} className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 美股
                    </button>
                </div>
            )}

        </div>
      </div>

      {/* List / Table */}
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className={`text-xs uppercase tracking-wider ${typeFilter === 'LIABILITIES' ? 'bg-rose-900/30 text-rose-300' : 'bg-slate-900/50 text-slate-400'}`}>
              <th className="p-4 font-medium">項目名稱</th>
              {typeFilter === 'STOCKS' && <th className="p-4 font-medium text-right">持倉數量</th>}
              <th className="p-4 font-medium text-right">
                  {typeFilter === 'LIABILITIES' ? '剩餘餘額' : '現價 / 總值'}
              </th>
              {typeFilter === 'LIABILITIES' ? (
                   <th className="p-4 font-medium text-right">利率 (參考)</th>
              ) : (
                  <th className="p-4 font-medium text-right">佔比</th>
              )}
              {typeFilter === 'STOCKS' && <th className="p-4 font-medium text-right">未實現損益</th>}
               <th className="p-4 font-medium text-right w-24">操作</th>
            </tr>
          </thead>
          <tbody className={`divide-y text-sm ${typeFilter === 'LIABILITIES' ? 'divide-rose-900/30' : 'divide-slate-700/50'}`}>
            {filteredAssets.length === 0 ? (
                <tr>
                    <td colSpan={6} className="p-8 text-center text-slate-500">
                         {typeFilter === 'LIABILITIES' ? '目前沒有負債紀錄。' : '沒有相關資產。'}
                    </td>
                </tr>
            ) : (
                filteredAssets.map(asset => {
                    const symbol = getCurrencySymbol(asset.type);
                    const gainInfo = calculateGain(asset);
                    const isPositive = gainInfo.gain >= 0;

                    // Logic to handle value calculation unified
                    const isLoan = asset.type === AssetType.LOAN_TWD;
                    const isCash = asset.type.includes('CASH');
                    const rawValue = (isCash || isLoan) ? asset.currentPrice : (asset.shares * asset.currentPrice);

                    const isUsAsset = (asset.type === AssetType.US_STOCK || asset.type === AssetType.CASH_USD);
                    const valueInTwd = isUsAsset ? rawValue * exchangeRate : rawValue;

                    const percentOfCategory = totalCategoryValueTwd > 0 
                        ? (valueInTwd / totalCategoryValueTwd) * 100 
                        : 0;

                    return (
                    <tr key={asset.id} className={`transition-colors group ${typeFilter === 'LIABILITIES' ? 'hover:bg-rose-900/20' : 'hover:bg-slate-700/30'}`}>
                        <td className="p-4">
                        <div className="flex items-center gap-3">
                            <div className={`w-2 h-8 rounded-full ${
                                asset.type === AssetType.TW_STOCK ? 'bg-emerald-500' : 
                                asset.type === AssetType.US_STOCK ? 'bg-blue-500' : 
                                asset.type === AssetType.LOAN_TWD ? 'bg-rose-500' : 'bg-amber-500'
                            }`}></div>
                            <div>
                                <div className="font-semibold text-white">{asset.name}</div>
                                <div className="text-xs text-slate-400">
                                    {asset.note || (asset.type.includes('US') ? '美股' : asset.type.includes('TW') ? '台股' : isLoan ? '負債' : '現金')}
                                </div>
                            </div>
                        </div>
                        </td>
                        {typeFilter === 'STOCKS' && (
                            <td className="p-4 text-right">
                                <div className="text-white">{asset.shares.toLocaleString()}</div>
                                <div className="text-xs text-slate-500">均價: {symbol}{asset.costBasis.toLocaleString()}</div>
                            </td>
                        )}
                        <td className="p-4 text-right">
                            <div className={`font-medium ${isLoan ? 'text-rose-300' : 'text-white'}`}>
                                {symbol}{rawValue.toLocaleString(undefined, { maximumFractionDigits: 2 })}
                            </div>
                             {typeFilter === 'STOCKS' && (
                                <div className="text-xs text-slate-500">
                                   現價: {asset.currentPrice.toLocaleString()}
                                </div>
                             )}
                             {isUsAsset && (
                                 <div className="text-xs text-slate-400 mt-0.5">
                                     ≈ NT${Math.round(valueInTwd).toLocaleString()}
                                 </div>
                             )}
                        </td>

                         <td className="p-4 text-right">
                            {isLoan ? (
                                <div className="text-slate-400">
                                    {asset.costBasis}%
                                </div>
                            ) : (
                                <div className="flex items-center justify-end gap-1 text-indigo-300 font-medium">
                                    <PieChart size={12} />
                                    {percentOfCategory.toFixed(1)}%
                                </div>
                            )}
                        </td>

                        {typeFilter === 'STOCKS' && (
                            <td className="p-4 text-right">
                                <div className={`flex items-center justify-end gap-1 font-medium ${isPositive ? 'text-emerald-400' : 'text-rose-400'}`}>
                                    {isPositive ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                    {Math.abs(gainInfo.percent).toFixed(2)}%
                                </div>
                                <div className={`text-xs ${isPositive ? 'text-emerald-500/70' : 'text-rose-500/70'}`}>
                                    {isPositive ? '+' : '-'}{symbol}{Math.abs(gainInfo.gain).toLocaleString(undefined, { maximumFractionDigits: 0 })}
                                </div>
                            </td>
                        )}
                        <td className="p-4 text-right">
                            <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => onEdit(asset)} className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-600 rounded">
                                    <Edit2 size={16} />
                                </button>
                                <button onClick={() => onDelete(asset.id)} className="p-1.5 text-slate-400 hover:text-rose-400 hover:bg-slate-600 rounded">
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </td>
                    </tr>
                    );
                })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AssetList;

import React, { useState } from 'react';
import { HistoryRecord } from '../types';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Legend } from 'recharts';
import { Calendar, Edit2, Save, X } from 'lucide-react';

interface HistoryTrackerProps {
  history: HistoryRecord[];
  onUpdateRecord: (record: HistoryRecord) => void;
}

const HistoryTracker: React.FC<HistoryTrackerProps> = ({ history, onUpdateRecord }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<HistoryRecord>>({});

  // Sort history by date ascending for chart
  const sortedHistory = [...history].sort((a, b) => a.date.localeCompare(b.date));

  const startEdit = (record: HistoryRecord) => {
    setEditingId(record.id);
    setEditForm({ ...record });
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  const saveEdit = () => {
    if (editingId && editForm.totalAssets !== undefined && editForm.totalLiabilities !== undefined) {
      const netWorth = Number(editForm.totalAssets) - Number(editForm.totalLiabilities);
      onUpdateRecord({
        ...editForm as HistoryRecord,
        netWorth: netWorth
      });
      setEditingId(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Chart Section */}
      <div className="bg-slate-800 p-6 rounded-2xl shadow-lg border border-slate-700/50">
        <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
            <Calendar className="text-indigo-400" />
            資產淨值趨勢 (Net Worth Trend)
        </h2>

        <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={sortedHistory} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                    <defs>
                        <linearGradient id="colorNet" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.4}/>
                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                        </linearGradient>
                    </defs>
                    <XAxis 
                        dataKey="date" 
                        stroke="#94a3b8" 
                        tick={{fill: '#94a3b8', fontSize: 12}}
                        tickLine={false}
                        axisLine={false}
                    />
                    <YAxis 
                        stroke="#94a3b8" 
                        tick={{fill: '#94a3b8', fontSize: 12}}
                        tickFormatter={(val) => `${(val/10000).toFixed(0)}萬`}
                        tickLine={false}
                        axisLine={false}
                    />
                    <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
