import React, { useState, useEffect } from 'react';
import { Asset, AssetType } from '../types';
import { X, Search, Loader2 } from 'lucide-react';
import { fetchStockPrice } from '../services/geminiService';

interface AssetModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (asset: Omit<Asset, 'id'> | Asset) => void;
  initialType?: AssetType;
  editingAsset?: Asset;
}

const AssetModal: React.FC<AssetModalProps> = ({ isOpen, onClose, onSave, initialType, editingAsset }) => {
  const [formData, setFormData] = useState<Partial<Asset>>({
    name: '',
    shares: 0,
    costBasis: 0,
    currentPrice: 0,
    note: ''
  });
  const [isFetchingPrice, setIsFetchingPrice] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (editingAsset) {
        setFormData(editingAsset);
      } else {
        setFormData({
            type: initialType || AssetType.TW_STOCK,
            name: '',
            shares: 0,
            costBasis: 0,
            currentPrice: 0,
            note: ''
        });
      }
    }
  }, [isOpen, editingAsset, initialType]);

  if (!isOpen) return null;

  const type = formData.type;
  const isCash = type?.includes('CASH');
  const isLoan = type === AssetType.LOAN_TWD;
  const isStock = !isCash && !isLoan;

  const handleFetchPrice = async () => {
    if (!formData.name || !formData.type || !isStock) return;
    setIsFetchingPrice(true);
    try {
      const price = await fetchStockPrice(formData.name, formData.type);
      if (price !== null && price > 0) {
        setFormData(prev => ({ ...prev, currentPrice: price }));
      } else {
        alert("無法找到此資產的價格，請手動輸入。");
      }
    } catch (e) {
      console.error(e);
      alert("查詢發生錯誤。");
    } finally {
      setIsFetchingPrice(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return;

    // For cash/loan, shares are irrelevant, usually 1
    const payload = {
        ...formData,
        shares: (isCash || isLoan) ? 1 : Number(formData.shares),
        costBasis: Number(formData.costBasis),
        currentPrice: Number(formData.currentPrice),
    } as Asset;

    onSave(payload);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm">
      <div className="bg-slate-800 rounded-2xl w-full max-w-md shadow-2xl border border-slate-700">
        <div className="flex justify-between items-center p-6 border-b border-slate-700">
          <h2 className="text-xl font-bold text-white">
            {editingAsset ? '編輯項目' : (isLoan ? '新增負債' : '新增資產')}
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">
              {isCash ? '帳戶名稱' : isLoan ? '貸款名稱' : '代號 / 名稱'}
            </label>
            <input
              type="text"
              required
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
              placeholder={isCash ? "例如：XX 銀行活存" : isLoan ? "例如：XX 銀行信貸" : "例如：2330 或 AAPL"}
              value={formData.name}
              onChange={e => setFormData({ ...formData, name: e.target.value })}
            />
          </div>

          {isStock && (
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">持有股數</label>
                <input
                  type="number"
                  step="any"
                  required
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                  value={formData.shares}
                  onChange={e => setFormData({ ...formData, shares: parseFloat(e.target.value) })}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">平均成本</label>
                <input
                  type="number"
                  step="any"
                  required
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                  value={formData.costBasis}
                  onChange={e => setFormData({ ...formData, costBasis: parseFloat(e.target.value) })}
                />
              </div>
            </div>
          )}

          {isLoan && (
               <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">年利率 (%) <span className="text-slate-600 text-xs font-normal">僅供紀錄</span></label>
                <input
                  type="number"
                  step="0.01"
                  required
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                  value={formData.costBasis}
                  onChange={e => setFormData({ ...formData, costBasis: parseFloat(e.target.value) })}
                />
              </div>
          )}

          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">
              {isCash ? '總金額' : isLoan ? '剩餘未還金額' : '目前市價'}
            </label>
            <div className="flex gap-2">
                <input
                type="number"
                step="any"
                required
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                value={formData.currentPrice}
                onChange={e => setFormData({ ...formData, currentPrice: parseFloat(e.target.value) })}
                />
                {isStock && (
                    <button 
                        type="button"
                        onClick={handleFetchPrice}
                        disabled={isFetchingPrice || !formData.name}
                        className="bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-700 disabled:text-slate-500 text-white p-3 rounded-lg transition"
                        title="自動查詢股價"
                    >
                        {isFetchingPrice ? <Loader2 size={20} className="animate-spin" /> : <Search size={20} />}
                    </button>
                )}
            </div>
             {isCash && <p className="text-xs text-slate-500 mt-1">請輸入此帳戶的現金總額。</p>}
             {isLoan && <p className="text-xs text-slate-500 mt-1">請輸入目前剩餘的本金餘額。</p>}
             {isStock && <p className="text-xs text-slate-500 mt-1">點擊搜尋按鈕可自動抓取最新市價 (需輸入代號)。</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">備註 (選填)</label>
            <textarea
              className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none h-20 resize-none"
              value={formData.note || ''}
              onChange={e => setFormData({ ...formData, note: e.target.value })}
            />
          </div>

          <div className="pt-4 flex gap-3">
             <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-3 rounded-lg border border-slate-600 text-slate-300 hover:bg-slate-700 transition font-medium"
            >
              取消
            </button>
            <button
              type="submit"
              className={`flex-1 px-4 py-3 rounded-lg text-white transition font-medium shadow-lg ${isLoan ? 'bg-rose-600 hover:bg-rose-500 shadow-rose-500/20' : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/20'}`}
            >
              儲存
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AssetModal;

import React, { useState, useEffect, useMemo } from 'react';
import { Asset, AssetType, HistoryRecord } from './types';
import { DEFAULT_USD_TWD_RATE, MOCK_INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard';
import AssetList from './components/AssetList';
import AssetModal from './components/AssetModal';
import GeminiAdvisor from './components/GeminiAdvisor';
import CompoundCalculator from './components/CompoundCalculator';
import HistoryTracker from './components/HistoryTracker';
import { analyzePortfolioWithGemini, fetchStockPrice } from './services/geminiService';
import { Settings, WalletMinimal, RefreshCcw, TrendingUp, Calculator, LayoutDashboard, Eye, EyeOff, History, Landmark } from 'lucide-react';

type ViewMode = 'DASHBOARD' | 'HISTORY' | 'CALCULATOR';

const App: React.FC = () => {
  // --- State ---
  const [assets, setAssets] = useState<Asset[]>(() => {
    const saved = localStorage.getItem('wealthfolio_assets');
    return saved ? JSON.parse(saved) : (MOCK_INITIAL_DATA as Asset[]);
  });

  const [history, setHistory] = useState<HistoryRecord[]>(() => {
      const saved = localStorage.getItem('wealthfolio_history');
      return saved ? JSON.parse(saved) : [];
  });

  const [exchangeRate, setExchangeRate] = useState<number>(() => {
    const saved = localStorage.getItem('wealthfolio_rate');
    return saved ? parseFloat(saved) : DEFAULT_USD_TWD_RATE;
  });
  const [isRateLoading, setIsRateLoading] = useState(false);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<AssetType>(AssetType.TW_STOCK);
  const [editingAsset, setEditingAsset] = useState<Asset | undefined>(undefined);

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isUpdatingPrices, setIsUpdatingPrices] = useState(false);

  // View & Filter State
  const [view, setView] = useState<ViewMode>('DASHBOARD');
  const [showTwStocks, setShowTwStocks] = useState(true);
  const [showUsStocks, setShowUsStocks] = useState(true);

  // --- Effects ---
  useEffect(() => {
    localStorage.setItem('wealthfolio_assets', JSON.stringify(assets));
  }, [assets]);

  useEffect(() => {
      localStorage.setItem('wealthfolio_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('wealthfolio_rate', exchangeRate.toString());
  }, [exchangeRate]);

  // Fetch Exchange Rate on mount
  useEffect(() => {
    const fetchRate = async () => {
        setIsRateLoading(true);
        try {
            const res = await fetch('https://api.exchangerate-api.com/v4/latest/USD');
            const data = await res.json();
            if (data && data.rates && data.rates.TWD) {
                setExchangeRate(data.rates.TWD);
            }
        } catch (error) {
            console.error("Failed to fetch exchange rate:", error);
        } finally {
            setIsRateLoading(false);
        }
    };
    fetchRate();
  }, []);

  // --- Automatic History Snapshot Logic ---
  // Check once on mount if current month record exists
  useEffect(() => {
      const today = new Date();
      const currentMonthKey = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}`;

      const hasRecord = history.some(r => r.date === currentMonthKey);

      if (!hasRecord && assets.length > 0) {
          // Calculate current stats
          let totalAssets = 0;
          let totalLiabilities = 0;

          assets.forEach(asset => {
               const isLoan = asset.type === AssetType.LOAN_TWD;
               let val = 0;
               if (asset.type.includes('US')) {
                    val = (asset.type.includes('CASH') ? asset.currentPrice : (asset.shares * asset.currentPrice)) * exchangeRate;
               } else {
                    val = asset.type.includes('STOCK') ? (asset.shares * asset.currentPrice) : asset.currentPrice;
               }

               if (isLoan) {
                   totalLiabilities += val;
               } else {
                   totalAssets += val;
               }
          });

          const newRecord: HistoryRecord = {
              id: crypto.randomUUID(),
              date: currentMonthKey,
              totalAssets,
              totalLiabilities,
              netWorth: totalAssets - totalLiabilities,
              note: '自動建立 (Auto-snapshot)'
          };

          setHistory(prev => [...prev, newRecord]);
          console.log(`Auto-created history record for ${currentMonthKey}`);
      }
  }, [history.length]); // Dependency on length ensures we don't loop, but runs if history loads empty

  // --- Derived State (Filtering) ---
  const filteredAssets = useMemo(() => {
      return assets.filter(asset => {
          if (asset.type === AssetType.TW_STOCK && !showTwStocks) return false;
          if (asset.type === AssetType.US_STOCK && !showUsStocks) return false;
          return true;
      });
  }, [assets, showTwStocks, showUsStocks]);

  // Calculate Total Net Worth for the Calculator
  const currentNetWorth = useMemo(() => {
      let totalAssets = 0;
      let totalLoans = 0;
      filteredAssets.forEach(asset => {
          const isLoan = asset.type === AssetType.LOAN_TWD;
          let val = 0;
          if (asset.type.includes('US')) {
              val = (asset.type.includes('CASH') ? asset.currentPrice : (asset.shares * asset.currentPrice)) * exchangeRate;
          } else {
              val = asset.type.includes('STOCK') ? (asset.shares * asset.currentPrice) : asset.currentPrice;
          }
          if (isLoan) totalLoans += val;
          else totalAssets += val;
      });
      return totalAssets - totalLoans;
  }, [filteredAssets, exchangeRate]);

  // --- Handlers ---
  const handleAddAsset = (type: AssetType) => {
    setEditingAsset(undefined);
    setModalType(type);
    setIsModalOpen(true);
  };

  const handleEditAsset = (asset: Asset) => {
    setEditingAsset(asset);
    setModalType(asset.type);
    setIsModalOpen(true);
  };

  const handleSaveAsset = (assetData: Asset | Omit<Asset, 'id'>) => {
    if ('id' in assetData) {
      setAssets(prev => prev.map(a => a.id === assetData.id ? assetData : a));
    } else {
      const newAsset: Asset = { ...assetData, id: crypto.randomUUID() };
      setAssets(prev => [...prev, newAsset]);
    }
  };

  const handleDeleteAsset = (id: string) => {
    if (confirm('確定要刪除此項目嗎？')) {
      setAssets(prev => prev.filter(a => a.id !== id));
    }
  };

  const handleUpdateRecord = (updatedRecord: HistoryRecord) => {
      setHistory(prev => prev.map(r => r.id === updatedRecord.id ? updatedRecord : r));
  };

  const handleAnalyze = async () => {
    if (filteredAssets.length === 0) return;
    setIsAiLoading(true);
    try {
        const result = await analyzePortfolioWithGemini(filteredAssets, exchangeRate);
        setAiAnalysis(result);
    } catch (e) {
        setAiAnalysis("分析失敗。");
    } finally {
        setIsAiLoading(false);
    }
  };

  const handleRefreshRate = async () => {
      setIsRateLoading(true);
      try {
        const res = await fetch('https://api.exchangerate-api.com/v4/latest/USD');
        const data = await res.json();
        if (data && data.rates && data.rates.TWD) {
            setExchangeRate(data.rates.TWD);
        }
      } catch (error) {
          alert('無法更新匯率，請檢查網路連線。');
      } finally {
          setIsRateLoading(false);
      }
  };

  const handleUpdateAllPrices = async () => {
      setIsUpdatingPrices(true);
      try {
          const updatedAssets = await Promise.all(assets.map(async (asset) => {
              if (asset.type === AssetType.TW_STOCK || asset.type === AssetType.US_STOCK) {
                  const newPrice = await fetchStockPrice(asset.name, asset.type);
                  if (newPrice !== null && newPrice > 0) {
                      return { ...asset, currentPrice: newPrice };
                  }
              }
              return asset;
          }));
          setAssets(updatedAssets);
      } catch (error) {
          console.error("Failed to update all prices", error);
      } finally {
          setIsUpdatingPrices(false);
      }
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Navbar */}
      <nav className="bg-slate-900/80 backdrop-blur-md border-b border-slate-800 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between h-auto md:h-16 py-2 md:py-0 gap-3">
            <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <div className="bg-indigo-600 p-2 rounded-lg">
                        <WalletMinimal className="text-white" size={20} />
                    </div>
                    <h1 className="text-xl font-bold tracking-tight text-white hidden sm:block">WealthFolio</h1>
                </div>

                {/* View Switcher */}
                <div className="flex bg-slate-800 p-1 rounded-lg overflow-x-auto no-scrollbar">
                    <button 
                        onClick={() => setView('DASHBOARD')}
                        className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition whitespace-nowrap ${view === 'DASHBOARD' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
                    >
                        <LayoutDashboard size={14} />
                        總覽
                    </button>
                    <button 
                        onClick={() => setView('HISTORY')}
                        className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition whitespace-nowrap ${view === 'HISTORY' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
                    >
                        <History size={14} />
                        歷史
                    </button>
                    <button 
                        onClick={() => setView('CALCULATOR')}
                        className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition whitespace-nowrap ${view === 'CALCULATOR' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
                    >
                        <Calculator size={14} />
                        試算
                    </button>
                </div>
            </div>

            <div className="flex items-center gap-2 sm:gap-4 overflow-x-auto no-scrollbar w-full md:w-auto">
                 {/* Filters */}
                 {view === 'DASHBOARD' && (
                    <div className="flex items-center gap-1 bg-slate-800 p-1 rounded-lg border border-slate-700/50">
                        <button 
                            onClick={() => setShowTwStocks(!showTwStocks)}
                            className={`flex items-center gap-1 px-2 py-1 rounded text-xs font-medium transition ${showTwStocks ? 'bg-emerald-600/20 text-emerald-400' : 'text-slate-500 hover:text-slate-300'}`}
                            title={showTwStocks ? "隱藏台股" : "顯示台股"}
                        >
                            {showTwStocks ? <Eye size={14} /> : <EyeOff size={14} />}
                            台股
                        </button>
                        <button 
                            onClick={() => setShowUsStocks(!showUsStocks)}
                            className={`flex items-center gap-1 px-2 py-1 rounded text-xs font-medium transition ${showUsStocks ? 'bg-blue-600/20 text-blue-400' : 'text-slate-500 hover:text-slate-300'}`}
                            title={showUsStocks ? "隱藏美股" : "顯示美股"}
                        >
                            {showUsStocks ? <Eye size={14} /> : <EyeOff size={14} />}
                            美股
                        </button>
                    </div>
                 )}

                 <button 
                    onClick={handleUpdateAllPrices}
                    disabled={isUpdatingPrices}
                    className="flex-shrink-0 flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-600/10 text-emerald-400 border border-emerald-600/30 hover:bg-emerald-600/20 transition disabled:opacity-50"
                  >
                     <TrendingUp size={14} className={isUpdatingPrices ? 'animate-spin' : ''} />
                     <span className="text-xs font-semibold hidden lg:inline">{isUpdatingPrices ? '更新中...' : '更新股價'}</span>
                 </button>

                <div className="flex-shrink-0 flex items-center gap-4 bg-slate-800 px-3 py-1.5 rounded-full border border-slate-700">
                   <Settings size={14} className="text-slate-400" />
                   <div className="flex items-center gap-2 text-sm text-slate-300">
                      <span className="text-xs font-semibold text-slate-500 uppercase hidden lg:inline">匯率</span>
                      <div className="relative group">
                        <input 
                            type="number" 
                            value={exchangeRate} 
                            onChange={(e) => setExchangeRate(parseFloat(e.target.value) || 0)}
                            className="w-16 bg-transparent text-right font-mono border-b border-slate-600 focus:border-indigo-500 focus:outline-none"
                        />
                      </div>
                      <button 
                        onClick={handleRefreshRate} 
                        disabled={isRateLoading}
                        className={`text-slate-400 hover:text-white transition ${isRateLoading ? 'animate-spin' : ''}`}
                        title="更新匯率"
                      >
                          <RefreshCcw size={14} />
                      </button>
                   </div>
                </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">

        {view === 'DASHBOARD' && (
            <>
                {/* Advisor Section */}
                <GeminiAdvisor 
                    analysis={aiAnalysis} 
                    loading={isAiLoading} 
                    onAnalyze={handleAnalyze} 
                    hasAssets={filteredAssets.length > 0}
                />

                {/* Dashboard Section */}
                <Dashboard assets={filteredAssets} exchangeRate={exchangeRate} />

                {/* Asset Lists */}
                <div className="grid grid-cols-1 gap-8">
                     {/* Row 1: Stocks & Cash */}
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        <AssetList 
                            typeFilter="STOCKS" 
                            assets={filteredAssets} 
                            exchangeRate={exchangeRate}
                            onAdd={handleAddAsset}
                            onDelete={handleDeleteAsset}
                            onEdit={handleEditAsset}
                        />
                         <AssetList 
                            typeFilter="CASH" 
                            assets={filteredAssets} 
                            exchangeRate={exchangeRate}
                            onAdd={handleAddAsset}
                            onDelete={handleDeleteAsset}
                            onEdit={handleEditAsset}
                        />
                     </div>

                     {/* Row 2: Liabilities */}
                     <AssetList 
                        typeFilter="LIABILITIES" 
                        assets={filteredAssets} 
                        exchangeRate={exchangeRate}
                        onAdd={handleAddAsset}
                        onDelete={handleDeleteAsset}
                        onEdit={handleEditAsset}
                    />
                </div>
            </>
        )}

        {view === 'HISTORY' && (
             <HistoryTracker history={history} onUpdateRecord={handleUpdateRecord} />
        )}

        {view === 'CALCULATOR' && (
            <CompoundCalculator initialPrincipal={currentNetWorth > 0 ? currentNetWorth : 0} />
        )}

      </main>

      {/* Modals */}
      <AssetModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSaveAsset}
        initialType={modalType}
        editingAsset={editingAsset}
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Asset, AssetType } from '../types';
import { Trash2, Edit2, Plus, TrendingUp, TrendingDown, PieChart, Banknote } from 'lucide-react';

interface AssetListProps {
  assets: Asset[];
  typeFilter: 'STOCKS' | 'CASH' | 'LIABILITIES';
  exchangeRate: number;
  onDelete: (id: string) => void;
  onEdit: (asset: Asset) => void;
  onAdd: (type: AssetType) => void;
}

const AssetList: React.FC<AssetListProps> = ({ assets, typeFilter, exchangeRate, onDelete, onEdit, onAdd }) => {
  const [activeTab, setActiveTab] = useState<'ALL' | 'TW' | 'US'>('ALL');

  // Calculate Total Value for % calculation
  const totalCategoryValueTwd = useMemo(() => {
    return assets.reduce((sum, asset) => {
      // Filter sum based on current list type
      const isStock = asset.type === AssetType.TW_STOCK || asset.type === AssetType.US_STOCK;
      const isCash = asset.type === AssetType.CASH_TWD || asset.type === AssetType.CASH_USD;
      const isLoan = asset.type === AssetType.LOAN_TWD;

      if (typeFilter === 'STOCKS' && !isStock) return sum;
      if (typeFilter === 'CASH' && !isCash) return sum;
      if (typeFilter === 'LIABILITIES' && !isLoan) return sum;

      let val = 0;
      if (asset.type.includes('US')) {
        val = (asset.type.includes('CASH') ? asset.currentPrice : (asset.shares * asset.currentPrice)) * exchangeRate;
      } else {
         val = asset.type.includes('STOCK') ? (asset.shares * asset.currentPrice) : asset.currentPrice;
      }
      return sum + val;
    }, 0);
  }, [assets, exchangeRate, typeFilter]);

  const filteredAssets = assets.filter(asset => {
    if (typeFilter === 'LIABILITIES') {
        return asset.type === AssetType.LOAN_TWD;
    }
    if (typeFilter === 'CASH') {
      return asset.type === AssetType.CASH_TWD || asset.type === AssetType.CASH_USD;
    }
    // Stock Logic
    if (activeTab === 'TW') return asset.type === AssetType.TW_STOCK;
    if (activeTab === 'US') return asset.type === AssetType.US_STOCK;
    return asset.type === AssetType.TW_STOCK || asset.type === AssetType.US_STOCK;
  });

  const getCurrencySymbol = (type: AssetType) => {
    return (type === AssetType.US_STOCK || type === AssetType.CASH_USD) ? 'US$' : 'NT$';
  };

  const calculateGain = (asset: Asset) => {
    if (asset.type.includes('CASH') || asset.type.includes('LOAN')) return { gain: 0, percent: 0 };
    const currentVal = asset.shares * asset.currentPrice;
    const costVal = asset.shares * asset.costBasis;
    const gain = currentVal - costVal;
    const percent = costVal > 0 ? (gain / costVal) * 100 : 0;
    return { gain, percent };
  };

  const getHeaderTitle = () => {
      switch(typeFilter) {
          case 'STOCKS': return '證券部位 (Stock Holdings)';
          case 'CASH': return '現金部位 (Cash Positions)';
          case 'LIABILITIES': return '負債/信貸 (Liabilities)';
      }
  };

  const getHeaderDesc = () => {
    switch(typeFilter) {
        case 'STOCKS': return '管理你的股票與 ETF';
        case 'CASH': return '管理你的流動資金';
        case 'LIABILITIES': return '管理信貸與其他負債';
    }
  };

  return (
    <div className={`rounded-2xl shadow-lg overflow-hidden ${typeFilter === 'LIABILITIES' ? 'bg-rose-950/20 border border-rose-900/50' : 'bg-slate-800'}`}>
      {/* Header & Tabs */}
      <div className="p-6 border-b border-slate-700 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h3 className={`text-xl font-bold mb-1 ${typeFilter === 'LIABILITIES' ? 'text-rose-100' : 'text-white'}`}>
            {getHeaderTitle()}
          </h3>
          <p className={`text-sm ${typeFilter === 'LIABILITIES' ? 'text-rose-300/70' : 'text-slate-400'}`}>{getHeaderDesc()}</p>
        </div>

        <div className="flex items-center gap-3">
            {typeFilter === 'STOCKS' && (
                <div className="bg-slate-900 p-1 rounded-lg flex text-xs font-medium">
                    {(['ALL', 'TW', 'US'] as const).map(tab => (
                        <button
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`px-3 py-1.5 rounded-md transition-colors ${activeTab === tab ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                        >
                            {tab === 'TW' ? '🇹🇼 台股' : tab === 'US' ? '🇺🇸 美股' : '全部'}
                        </button>
                    ))}
                </div>
            )}

            {typeFilter === 'CASH' && (
                <div className="flex gap-2">
                     <button onClick={() => onAdd(AssetType.CASH_TWD)} className="bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 台幣
                    </button>
                    <button onClick={() => onAdd(AssetType.CASH_USD)} className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 美金
                    </button>
                </div>
            )}

            {typeFilter === 'LIABILITIES' && (
                <button onClick={() => onAdd(AssetType.LOAN_TWD)} className="bg-rose-600 hover:bg-rose-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                    <Plus size={16} /> 新增負債
                </button>
            )}

            {typeFilter === 'STOCKS' && (
                 <div className="flex gap-2">
                     <button onClick={() => onAdd(AssetType.TW_STOCK)} className="bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 台股
                    </button>
                    <button onClick={() => onAdd(AssetType.US_STOCK)} className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1 transition">
                        <Plus size={16} /> 美股
                    </button>
                </div>
            )}

        </div>
      </div>

      {/* List / Table */}
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className={`text-xs uppercase tracking-wider ${typeFilter === 'LIABILITIES' ? 'bg-rose-900/30 text-rose-300' : 'bg-slate-900/50 text-slate-400'}`}>
              <th className="p-4 font-medium">項目名稱</th>
              {typeFilter === 'STOCKS' && <th className="p-4 font-medium text-right">持倉數量</th>}
              <th className="p-4 font-medium text-right">
                  {typeFilter === 'LIABILITIES' ? '剩餘餘額' : '現價 / 總值'}
              </th>
              {typeFilter === 'LIABILITIES' ? (
                   <th className="p-4 font-medium text-right">利率 (參考)</th>
              ) : (
                  <th className="p-4 font-medium text-right">佔比</th>
              )}
              {typeFilter === 'STOCKS' && <th className="p-4 font-medium text-right">未實現損益</th>}
               <th className="p-4 font-medium text-right w-24">操作</th>
            </tr>
          </thead>
          <tbody className={`divide-y text-sm ${typeFilter === 'LIABILITIES' ? 'divide-rose-900/30' : 'divide-slate-700/50'}`}>
            {filteredAssets.length === 0 ? (
                <tr>
                    <td colSpan={6} className="p-8 text-center text-slate-500">
                         {typeFilter === 'LIABILITIES' ? '目前沒有負債紀錄。' : '沒有相關資產。'}
                    </td>
                </tr>
            ) : (
                filteredAssets.map(asset => {
                    const symbol = getCurrencySymbol(asset.type);
                    const gainInfo = calculateGain(asset);
                    const isPositive = gainInfo.gain >= 0;

                    // Logic to handle value calculation unified
                    const isLoan = asset.type === AssetType.LOAN_TWD;
                    const isCash = asset.type.includes('CASH');
                    const rawValue = (isCash || isLoan) ? asset.currentPrice : (asset.shares * asset.currentPrice);

                    const isUsAsset = (asset.type === AssetType.US_STOCK || asset.type === AssetType.CASH_USD);
                    const valueInTwd = isUsAsset ? rawValue * exchangeRate : rawValue;

                    const percentOfCategory = totalCategoryValueTwd > 0 
                        ? (valueInTwd / totalCategoryValueTwd) * 100 
                        : 0;

                    return (
                    <tr key={asset.id} className={`transition-colors group ${typeFilter === 'LIABILITIES' ? 'hover:bg-rose-900/20' : 'hover:bg-slate-700/30'}`}>
                        <td className="p-4">
                        <div className="flex items-center gap-3">
                            <div className={`w-2 h-8 rounded-full ${
                                asset.type === AssetType.TW_STOCK ? 'bg-emerald-500' : 
                                asset.type === AssetType.US_STOCK ? 'bg-blue-500' : 
                                asset.type === AssetType.LOAN_TWD ? 'bg-rose-500' : 'bg-amber-500'
                            }`}></div>
                            <div>
                                <div className="font-semibold text-white">{asset.name}</div>
                                <div className="text-xs text-slate-400">
                                    {asset.note || (asset.type.includes('US') ? '美股' : asset.type.includes('TW') ? '台股' : isLoan ? '負債' : '現金')}
                                </div>
                            </div>
                        </div>
                        </td>
                        {typeFilter === 'STOCKS' && (
                            <td className="p-4 text-right">
                                <div className="text-white">{asset.shares.toLocaleString()}</div>
                                <div className="text-xs text-slate-500">均價: {symbol}{asset.costBasis.toLocaleString()}</div>
                            </td>
                        )}
                        <td className="p-4 text-right">
                            <div className={`font-medium ${isLoan ? 'text-rose-300' : 'text-white'}`}>
                                {symbol}{rawValue.toLocaleString(undefined, { maximumFractionDigits: 2 })}
                            </div>
                             {typeFilter === 'STOCKS' && (
                                <div className="text-xs text-slate-500">
                                   現價: {asset.currentPrice.toLocaleString()}
                                </div>
                             )}
                             {isUsAsset && (
                                 <div className="text-xs text-slate-400 mt-0.5">
                                     ≈ NT${Math.round(valueInTwd).toLocaleString()}
                                 </div>
                             )}
                        </td>

                         <td className="p-4 text-right">
                            {isLoan ? (
                                <div className="text-slate-400">
                                    {asset.costBasis}%
                                </div>
                            ) : (
                                <div className="flex items-center justify-end gap-1 text-indigo-300 font-medium">
                                    <PieChart size={12} />
                                    {percentOfCategory.toFixed(1)}%
                                </div>
                            )}
                        </td>

                        {typeFilter === 'STOCKS' && (
                            <td className="p-4 text-right">
                                <div className={`flex items-center justify-end gap-1 font-medium ${isPositive ? 'text-emerald-400' : 'text-rose-400'}`}>
                                    {isPositive ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                    {Math.abs(gainInfo.percent).toFixed(2)}%
                                </div>
                                <div className={`text-xs ${isPositive ? 'text-emerald-500/70' : 'text-rose-500/70'}`}>
                                    {isPositive ? '+' : '-'}{symbol}{Math.abs(gainInfo.gain).toLocaleString(undefined, { maximumFractionDigits: 0 })}
                                </div>
                            </td>
                        )}
                        <td className="p-4 text-right">
                            <div className="flex items-center justify-end gap-2 opacity-100 lg:opacity-0 lg:group-hover:opacity-100 transition-opacity">
                                <button 
                                    type="button"
                                    onClick={(e) => { e.stopPropagation(); onEdit(asset); }} 
                                    className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-600 rounded"
                                >
                                    <Edit2 size={16} />
                                </button>
                                <button 
                                    type="button"
                                    onClick={(e) => { e.stopPropagation(); onDelete(asset.id); }} 
                                    className="p-1.5 text-slate-400 hover:text-rose-400 hover:bg-slate-600 rounded"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </td>
                    </tr>
                    );
                })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AssetList;

import React, { useState, useEffect, useMemo } from 'react';
import { Asset, AssetType, HistoryRecord } from './types';
import { DEFAULT_USD_TWD_RATE, MOCK_INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard';
import AssetList from './components/AssetList';
import AssetModal from './components/AssetModal';
import GeminiAdvisor from './components/GeminiAdvisor';
import CompoundCalculator from './components/CompoundCalculator';
import HistoryTracker from './components/HistoryTracker';
import { analyzePortfolioWithGemini, fetchStockPrice } from './services/geminiService';
import { Settings, WalletMinimal, RefreshCcw, TrendingUp, Calculator, LayoutDashboard, Eye, EyeOff, History, Landmark } from 'lucide-react';

type ViewMode = 'DASHBOARD' | 'HISTORY' | 'CALCULATOR';

const App: React.FC = () => {
  // --- State ---
  const [assets, setAssets] = useState<Asset[]>(() => {
    const saved = localStorage.getItem('wealthfolio_assets');
    return saved ? JSON.parse(saved) : (MOCK_INITIAL_DATA as Asset[]);
  });

  const [history, setHistory] = useState<HistoryRecord[]>(() => {
      const saved = localStorage.getItem('wealthfolio_history');
      return saved ? JSON.parse(saved) : [];
  });

  const [exchangeRate, setExchangeRate] = useState<number>(() => {
    const saved = localStorage.getItem('wealthfolio_rate');
    return saved ? parseFloat(saved) : DEFAULT_USD_TWD_RATE;
  });
  const [isRateLoading, setIsRateLoading] = useState(false);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<AssetType>(AssetType.TW_STOCK);
  const [editingAsset, setEditingAsset] = useState<Asset | undefined>(undefined);

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isUpdatingPrices, setIsUpdatingPrices] = useState(false);

  // View & Filter State
  const [view, setView] = useState<ViewMode>('DASHBOARD');
  const [showTwStocks, setShowTwStocks] = useState(true);
  const [showUsStocks, setShowUsStocks] = useState(true);

  // --- Effects ---
  useEffect(() => {
    localStorage.setItem('wealthfolio_assets', JSON.stringify(assets));
  }, [assets]);

  useEffect(() => {
      localStorage.setItem('wealthfolio_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('wealthfolio_rate', exchangeRate.toString());
  }, [exchangeRate]);

  // Fetch Exchange Rate on mount
  useEffect(() => {
    const fetchRate = async () => {
        setIsRateLoading(true);
        try {
            const res = await fetch('https://api.exchangerate-api.com/v4/latest/USD');
            const data = await res.json();
            if (data && data.rates && data.rates.TWD) {
                setExchangeRate(data.rates.TWD);
            }
        } catch (error) {
            console.error("Failed to fetch exchange rate:", error);
        } finally {
            setIsRateLoading(false);
        }
    };
    fetchRate();
  }, []);

  // --- Automatic History Snapshot Logic ---
  // Check once on mount if current month record exists
  useEffect(() => {
      const today = new Date();
      const currentMonthKey = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}`;

      const hasRecord = history.some(r => r.date === currentMonthKey);

      if (!hasRecord && assets.length > 0) {
          // Calculate current stats
          let totalAssets = 0;
          let totalLiabilities = 0;

          assets.forEach(asset => {
               const isLoan = asset.type === AssetType.LOAN_TWD;
               let val = 0;
               if (asset.type.includes('US')) {
                    val = (asset.type.includes('CASH') ? asset.currentPrice : (asset.shares * asset.currentPrice)) * exchangeRate;
               } else {
                    val = asset.type.includes('STOCK') ? (asset.shares * asset.currentPrice) : asset.currentPrice;
               }

               if (isLoan) {
                   totalLiabilities += val;
               } else {
                   totalAssets += val;
               }
          });

          const newRecord: HistoryRecord = {
              id: crypto.randomUUID(),
              date: currentMonthKey,
              totalAssets,
              totalLiabilities,
              netWorth: totalAssets - totalLiabilities,
              note: '自動建立 (Auto-snapshot)'
          };

          setHistory(prev => [...prev, newRecord]);
          console.log(`Auto-created history record for ${currentMonthKey}`);
      }
  }, [history.length]); // Dependency on length ensures we don't loop, but runs if history loads empty

  // --- Derived State (Filtering) ---
  const filteredAssets = useMemo(() => {
      return assets.filter(asset => {
          if (asset.type === AssetType.TW_STOCK && !showTwStocks) return false;
          if (asset.type === AssetType.US_STOCK && !showUsStocks) return false;
          return true;
      });
  }, [assets, showTwStocks, showUsStocks]);

  // Calculate Total Net Worth for the Calculator
  const currentNetWorth = useMemo(() => {
      let totalAssets = 0;
      let totalLoans = 0;
      filteredAssets.forEach(asset => {
          const isLoan = asset.type === AssetType.LOAN_TWD;
          let val = 0;
          if (asset.type.includes('US')) {
              val = (asset.type.includes('CASH') ? asset.currentPrice : (asset.shares * asset.currentPrice)) * exchangeRate;
          } else {
              val = asset.type.includes('STOCK') ? (asset.shares * asset.currentPrice) : asset.currentPrice;
          }
          if (isLoan) totalLoans += val;
          else totalAssets += val;
      });
      return totalAssets - totalLoans;
  }, [filteredAssets, exchangeRate]);

  // --- Handlers ---
  const handleAddAsset = (type: AssetType) => {
    setEditingAsset(undefined);
    setModalType(type);
    setIsModalOpen(true);
  };

  const handleEditAsset = (asset: Asset) => {
    setEditingAsset(asset);
    setModalType(asset.type);
    setIsModalOpen(true);
  };

  const handleSaveAsset = (assetData: Asset | Omit<Asset, 'id'>) => {
    if ('id' in assetData) {
      setAssets(prev => prev.map(a => a.id === assetData.id ? assetData : a));
    } else {
      const newAsset: Asset = { ...assetData, id: crypto.randomUUID() };
      setAssets(prev => [...prev, newAsset]);
    }
  };

  const handleDeleteAsset = (id: string) => {
    if (window.confirm('確定要刪除此項目嗎？')) {
      setAssets(prev => prev.filter(a => a.id !== id));
    }
  };

  const handleUpdateRecord = (updatedRecord: HistoryRecord) => {
      setHistory(prev => prev.map(r => r.id === updatedRecord.id ? updatedRecord : r));
  };

  const handleAnalyze = async () => {
    if (filteredAssets.length === 0) return;
    setIsAiLoading(true);
    try {
        const result = await analyzePortfolioWithGemini(filteredAssets, exchangeRate);
        setAiAnalysis(result);
    } catch (e) {
        setAiAnalysis("分析失敗。");
    } finally {
        setIsAiLoading(false);
    }
  };

  const handleRefreshRate = async () => {
      setIsRateLoading(true);
      try {
        const res = await fetch('https://api.exchangerate-api.com/v4/latest/USD');
        const data = await res.json();
        if (data && data.rates && data.rates.TWD) {
            setExchangeRate(data.rates.TWD);
        }
      } catch (error) {
          alert('無法更新匯率，請檢查網路連線。');
      } finally {
          setIsRateLoading(false);
      }
  };

  const handleUpdateAllPrices = async () => {
      setIsUpdatingPrices(true);
      try {
          const updatedAssets = await Promise.all(assets.map(async (asset) => {
              if (asset.type === AssetType.TW_STOCK || asset.type === AssetType.US_STOCK) {
                  const newPrice = await fetchStockPrice(asset.name, asset.type);
                  if (newPrice !== null && newPrice > 0) {
                      return { ...asset, currentPrice: newPrice };
                  }
              }
              return asset;
          }));
          setAssets(updatedAssets);
      } catch (error) {
          console.error("Failed to update all prices", error);
      } finally {
          setIsUpdatingPrices(false);
      }
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Navbar */}
      <nav className="bg-slate-900/80 backdrop-blur-md border-b border-slate-800 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between h-auto md:h-16 py-2 md:py-0 gap-3">
            <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <div className="bg-indigo-600 p-2 rounded-lg">
                        <WalletMinimal className="text-white" size={20} />
                    </div>
                    <h1 className="text-xl font-bold tracking-tight text-white hidden sm:block">WealthFolio</h1>
                </div>

                {/* View Switcher */}
                <div className="flex bg-slate-800 p-1 rounded-lg overflow-x-auto no-scrollbar">
                    <button 
                        onClick={() => setView('DASHBOARD')}
                        className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition whitespace-nowrap ${view === 'DASHBOARD' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
                    >
                        <LayoutDashboard size={14} />
                        總覽
                    </button>
                    <button 
                        onClick={() => setView('HISTORY')}
                        className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition whitespace-nowrap ${view === 'HISTORY' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
                    >
                        <History size={14} />
                        歷史
                    </button>
                    <button 
                        onClick={() => setView('CALCULATOR')}
                        className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition whitespace-nowrap ${view === 'CALCULATOR' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}
                    >
                        <Calculator size={14} />
                        試算
                    </button>
                </div>
            </div>

            <div className="flex items-center gap-2 sm:gap-4 overflow-x-auto no-scrollbar w-full md:w-auto">
                 {/* Filters */}
                 {view === 'DASHBOARD' && (
                    <div className="flex items-center gap-1 bg-slate-800 p-1 rounded-lg border border-slate-700/50">
                        <button 
                            onClick={() => setShowTwStocks(!showTwStocks)}
                            className={`flex items-center gap-1 px-2 py-1 rounded text-xs font-medium transition ${showTwStocks ? 'bg-emerald-600/20 text-emerald-400' : 'text-slate-500 hover:text-slate-300'}`}
                            title={showTwStocks ? "隱藏台股" : "顯示台股"}
                        >
                            {showTwStocks ? <Eye size={14} /> : <EyeOff size={14} />}
                            台股
                        </button>
                        <button 
                            onClick={() => setShowUsStocks(!showUsStocks)}
                            className={`flex items-center gap-1 px-2 py-1 rounded text-xs font-medium transition ${showUsStocks ? 'bg-blue-600/20 text-blue-400' : 'text-slate-500 hover:text-slate-300'}`}
                            title={showUsStocks ? "隱藏美股" : "顯示美股"}
                        >
                            {showUsStocks ? <Eye size={14} /> : <EyeOff size={14} />}
                            美股
                        </button>
                    </div>
                 )}

                 <button 
                    onClick={handleUpdateAllPrices}
                    disabled={isUpdatingPrices}
                    className="flex-shrink-0 flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-600/10 text-emerald-400 border border-emerald-600/30 hover:bg-emerald-600/20 transition disabled:opacity-50"
                  >
                     <TrendingUp size={14} className={isUpdatingPrices ? 'animate-spin' : ''} />
                     <span className="text-xs font-semibold hidden lg:inline">{isUpdatingPrices ? '更新中...' : '更新股價'}</span>
                 </button>

                <div className="flex-shrink-0 flex items-center gap-4 bg-slate-800 px-3 py-1.5 rounded-full border border-slate-700">
                   <Settings size={14} className="text-slate-400" />
                   <div className="flex items-center gap-2 text-sm text-slate-300">
                      <span className="text-xs font-semibold text-slate-500 uppercase hidden lg:inline">匯率</span>
                      <div className="relative group">
                        <input 
                            type="number" 
                            value={exchangeRate} 
                            onChange={(e) => setExchangeRate(parseFloat(e.target.value) || 0)}
                            className="w-16 bg-transparent text-right font-mono border-b border-slate-600 focus:border-indigo-500 focus:outline-none"
                        />
                      </div>
                      <button 
                        onClick={handleRefreshRate} 
                        disabled={isRateLoading}
                        className={`text-slate-400 hover:text-white transition ${isRateLoading ? 'animate-spin' : ''}`}
                        title="更新匯率"
                      >
                          <RefreshCcw size={14} />
                      </button>
                   </div>
                </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">

        {view === 'DASHBOARD' && (
            <>
                {/* Advisor Section */}
                <GeminiAdvisor 
                    analysis={aiAnalysis} 
                    loading={isAiLoading} 
                    onAnalyze={handleAnalyze} 
                    hasAssets={filteredAssets.length > 0}
                />

                {/* Dashboard Section */}
                <Dashboard assets={filteredAssets} exchangeRate={exchangeRate} />

                {/* Asset Lists */}
                <div className="grid grid-cols-1 gap-8">
                     {/* Row 1: Stocks & Cash */}
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        <AssetList 
                            typeFilter="STOCKS" 
                            assets={filteredAssets} 
                            exchangeRate={exchangeRate}
                            onAdd={handleAddAsset}
                            onDelete={handleDeleteAsset}
                            onEdit={handleEditAsset}
                        />
                         <AssetList 
                            typeFilter="CASH" 
                            assets={filteredAssets} 
                            exchangeRate={exchangeRate}
                            onAdd={handleAddAsset}
                            onDelete={handleDeleteAsset}
                            onEdit={handleEditAsset}
                        />
                     </div>

                     {/* Row 2: Liabilities */}
                     <AssetList 
                        typeFilter="LIABILITIES" 
                        assets={filteredAssets} 
                        exchangeRate={exchangeRate}
                        onAdd={handleAddAsset}
                        onDelete={handleDeleteAsset}
                        onEdit={handleEditAsset}
                    />
                </div>
            </>
        )}

        {view === 'HISTORY' && (
             <HistoryTracker history={history} onUpdateRecord={handleUpdateRecord} />
        )}

        {view === 'CALCULATOR' && (
            <CompoundCalculator initialPrincipal={currentNetWorth > 0 ? currentNetWorth : 0} />
        )}

      </main>

      {/* Modals */}
      <AssetModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSaveAsset}
        initialType={modalType}
        editingAsset={editingAsset}
      />
    </div>
  );
};

export default App;
